# Unit Tests for `snake_to_camel`

```python
import pytest


def snake_to_camel(s: str) -> str:
    parts = s.split('_')
    return parts[0] + ''.join(p.capitalize() for p in parts[1:])


class TestSnakeToCamelHappyPath:
    """Tests for typical, expected inputs."""

    def test_simple_two_word_snake_case(self):
        assert snake_to_camel("hello_world") == "helloWorld"

    def test_three_word_snake_case(self):
        assert snake_to_camel("my_variable_name") == "myVariableName"

    def test_many_word_snake_case(self):
        assert snake_to_camel("a_b_c_d_e") == "aBCDE"

    def test_single_word_no_underscore(self):
        assert snake_to_camel("hello") == "hello"

    def test_with_numbers(self):
        assert snake_to_camel("var_1_name") == "var1Name"

    def test_starts_lowercase_first_word_unchanged(self):
        # The first word's case is preserved (not capitalized)
        assert snake_to_camel("first_second") == "firstSecond"


class TestSnakeToCamelEdgeCases:
    """Tests for unusual but valid inputs."""

    def test_empty_string(self):
        assert snake_to_camel("") == ""

    def test_single_underscore(self):
        # "_" splits to ["", ""] -> "" + "".capitalize() == ""
        assert snake_to_camel("_") == ""

    def test_leading_underscore(self):
        # "_hello" splits to ["", "hello"] -> "" + "Hello"
        assert snake_to_camel("_hello") == "Hello"

    def test_trailing_underscore(self):
        # "hello_" splits to ["hello", ""] -> "hello" + ""
        assert snake_to_camel("hello_") == "hello"

    def test_double_underscore_in_middle(self):
        # "hello__world" splits to ["hello", "", "world"]
        # -> "hello" + "".capitalize() + "World" -> "helloWorld"
        assert snake_to_camel("hello__world") == "helloWorld"

    def test_multiple_consecutive_underscores(self):
        assert snake_to_camel("a___b") == "aB"

    def test_only_underscores(self):
        assert snake_to_camel("___") == ""

    def test_already_camel_case_input(self):
        # No underscores, returned as-is
        assert snake_to_camel("alreadyCamel") == "alreadyCamel"

    def test_uppercase_components_get_capitalized(self):
        # capitalize() lowercases trailing letters
        assert snake_to_camel("hello_WORLD") == "helloWorld"

    def test_first_word_uppercase_preserved(self):
        # First word is not modified, only joined as-is
        assert snake_to_camel("HELLO_world") == "HELLOWorld"

    def test_single_character_words(self):
        assert snake_to_camel("a_b") == "aB"

    def test_first_word_empty_with_content(self):
        assert snake_to_camel("_a_b") == "AB"

    def test_whitespace_within_word_preserved(self):
        # split is only on '_', spaces remain
        assert snake_to_camel("hello world_foo") == "hello worldFoo"

    def test_with_special_characters(self):
        assert snake_to_camel("hello_world!") == "helloWorld!"

    def test_unicode_characters(self):
        assert snake_to_camel("café_münchen") == "caféMünchen"

    def test_numeric_only_word(self):
        # "123".capitalize() == "123"
        assert snake_to_camel("foo_123") == "foo123"

    def test_word_starting_with_digit(self):
        # "1abc".capitalize() == "1abc" (digits aren't letters)
        assert snake_to_camel("foo_1abc") == "foo1abc"


class TestSnakeToCamelErrorCases:
    """Tests for invalid inputs that should raise errors."""

    def test_none_input_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            snake_to_camel(None)

    def test_integer_input_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            snake_to_camel(123)

    def test_list_input_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            snake_to_camel(["hello", "world"])

    def test_bytes_input_raises_type_error(self):
        # bytes.split returns list of bytes, then capitalize works,
        # but '+' between str and bytes fails
        with pytest.raises(TypeError):
            snake_to_camel(b"hello_world")

    def test_dict_input_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            snake_to_camel({"key": "value"})


@pytest.mark.parametrize("input_str,expected", [
    ("hello_world", "helloWorld"),
    ("a_b_c", "aBC"),
    ("", ""),
    ("single", "single"),
    ("_leading", "Leading"),
    ("trailing_", "trailing"),
    ("__double__", "Double"),
    ("snake_case_string", "snakeCaseString"),
    ("ALL_CAPS_HERE", "ALLCapsHere"),
    ("mix_OF_cases", "mixOfCases"),
])
def test_snake_to_camel_parametrized(input_str, expected):
    """Parametrized tests covering a variety of inputs."""
    assert snake_to_camel(input_str) == expected
